INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' atividade nos termos do n.º 5 do artigo 8.º, a declaração de rendimentos relativa ao período de tributação em que a mesma se verificou deve ser enviada até ao último dia do terceiro mês seguinte ao da data da cessação, independentemente de esse dia ser útil ou não útil, aplicando-se igualmente este prazo ao envio da declaração relativa ao período de tributação imediatamente anterior, quando ainda não tenham decorrido os prazos mencionados nos n.os 1 e 2.
