INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ão urbana destinadas a arrendamento, bem como para recuperação do parque habitacional degradado da titularidade dos municípios; ou
  c) 30 anos, em operações financiadas pelo Banco Europeu de Investimento (BEI).
  8 - ...
